import { describe, it, expect, beforeAll, afterAll } from "vitest";
import {
  setup,
  loadFixture,
  clearFixtures,
  type TestContext,
  assertMappingValue,
  assertTransactionRejected,
} from "@lionden/testing";

// TypeScript bindings — generated by `lionden compile` before tests run.
// This is the first example that uses typechain in tests.
import { createEscrow } from "../typechain/Escrow.js";

async function deployEscrow() {
  const ctx = await setup();
  try {
    await ctx.deploy("escrow", { noCompile: true });
    return { ctx };
  } catch (error) {
    await ctx.teardown();
    throw error;
  }
}

let ctx: TestContext | undefined;

beforeAll(async () => {
  const fixture = await loadFixture(deployEscrow);
  ctx = fixture.ctx;
});

afterAll(async () => {
  if (ctx) {
    await ctx.teardown();
  } else {
    clearFixtures();
  }
});

describe("escrow program (via typechain)", () => {
  const escrow = createEscrow();

  beforeAll(() => {
    escrow.connect(ctx!.lre);
  });

  describe("create_escrow", () => {
    it("creates an escrow with status 0", async () => {
      await escrow.create_escrowBroadcast(42n);

      await assertMappingValue(
        ctx!.connection,
        "escrow.aleo",
        "escrow_status",
        "42u64",
        "0u8",
      );
    });
  });

  describe("fund_escrow", () => {
    it("funds the escrow and transitions status to 1", async () => {
      await escrow.fund_escrowBroadcast(42n);

      await assertMappingValue(
        ctx!.connection,
        "escrow.aleo",
        "escrow_status",
        "42u64",
        "1u8",
      );
    });
  });

  describe("complete_escrow", () => {
    it("completes the escrow and transitions status to 2", async () => {
      await escrow.complete_escrowBroadcast(42n);

      await assertMappingValue(
        ctx!.connection,
        "escrow.aleo",
        "escrow_status",
        "42u64",
        "2u8",
      );
    });
  });

  describe("off-chain failure (transition assertion)", () => {
    it("rejects create_escrow with item_id 0 and writes no state", async () => {
      // Transition-level assert(item_id > 0u64) fires during local
      // computation — the call throws before any tx is broadcast.
      await expect(escrow.create_escrowBroadcast(0n)).rejects.toThrow();

      // No on-chain state was written
      const status = await escrow.getEscrow_status(0n);
      expect(status).toBeNull();
    });
  });

  describe("on-chain failure (finalizer assertion)", () => {
    it("rejects funding an already-funded escrow", async () => {
      // Setup: create and fund escrow 100
      await escrow.create_escrowBroadcast(100n);
      await escrow.fund_escrowBroadcast(100n);

      // Fund again — transition succeeds (no assertions in body),
      // but finalizer's assert_eq(status, 0u8) fails (status is 1).
      const result = await escrow.fund_escrowBroadcast(100n);
      await assertTransactionRejected(ctx!.connection, result.txId!);

      // State is unchanged — still "funded" (1)
      const status = await escrow.getEscrow_status(100n);
      expect(status).toBe(1);
    });
  });
});
